// Generated by Claude Opus 4.6

import { BackupInfo, BackupStatus } from '@eclipse-che/common';
import React from 'react';

import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';
import { constructWorkspace, Workspace } from '@/services/workspace-adapter';
import { DevWorkspaceBuilder } from '@/store/__mocks__/devWorkspaceBuilder';

import { BackupTab } from '..';

jest.mock('@/services/helpers/dates', () => ({
  formatDate: jest.fn(() => 'Jan 15, 2:30 p.m.'),
  formatRelativeDate: jest.fn(() => '2 hours ago'),
}));

jest.mock('@/components/BackupStatusBadge', () => ({
  BackupStatusBadge: (props: { status: string }) => (
    <span data-testid="backup-status-badge">{props.status}</span>
  ),
}));

jest.mock('@patternfly/react-core', () => {
  const actual = jest.requireActual('@patternfly/react-core');
  return {
    ...actual,
    ClipboardCopy: (props: { children: React.ReactNode }) => (
      <div data-testid="clipboard-copy">{props.children}</div>
    ),
  };
});

const mockFetchBackupStatus = jest.fn();

const { createSnapshot, renderComponent } = getComponentRenderer(getComponent);

describe('BackupTab', () => {
  let workspace: Workspace;

  beforeEach(() => {
    const devWorkspace = new DevWorkspaceBuilder()
      .withName('my-workspace')
      .withNamespace('user-namespace')
      .withUID('test-uid-123')
      .build();
    workspace = constructWorkspace(devWorkspace);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('data fetching', () => {
    test('should fetch backup status on mount', () => {
      renderComponent(workspace);

      expect(mockFetchBackupStatus).toHaveBeenCalledWith({
        namespace: workspace.namespace,
        workspaceUID: workspace.uid,
        workspaceName: workspace.name,
      });
    });

    test('should re-fetch when workspace UID changes', () => {
      const { reRenderComponent } = renderComponent(workspace);

      expect(mockFetchBackupStatus).toHaveBeenCalledTimes(1);

      const newDevWorkspace = new DevWorkspaceBuilder()
        .withName('other-workspace')
        .withNamespace('user-namespace')
        .withUID('different-uid-456')
        .build();
      const newWorkspace = constructWorkspace(newDevWorkspace);

      reRenderComponent(newWorkspace);

      expect(mockFetchBackupStatus).toHaveBeenCalledTimes(2);
      expect(mockFetchBackupStatus).toHaveBeenLastCalledWith({
        namespace: newWorkspace.namespace,
        workspaceUID: newWorkspace.uid,
        workspaceName: newWorkspace.name,
      });
    });

    test('should not re-fetch when workspace UID stays the same', () => {
      const { reRenderComponent } = renderComponent(workspace);

      expect(mockFetchBackupStatus).toHaveBeenCalledTimes(1);

      reRenderComponent(workspace, { isLoading: true });

      expect(mockFetchBackupStatus).toHaveBeenCalledTimes(1);
    });
  });

  describe('loading state', () => {
    test('should show spinner when loading with no backup data', () => {
      renderComponent(workspace, { isLoading: true });

      expect(screen.getByLabelText('Loading backup information')).toBeInTheDocument();
    });

    test('snapshot - loading', () => {
      const snapshot = createSnapshot(workspace, { isLoading: true });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('error state', () => {
    test('should show error alert', () => {
      renderComponent(workspace, { error: 'Network error occurred' });

      expect(screen.getByText('Failed to load backup information')).toBeInTheDocument();
      expect(screen.getByText('Network error occurred')).toBeInTheDocument();
    });

    test('snapshot - error', () => {
      const snapshot = createSnapshot(workspace, { error: 'Network error occurred' });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('no backup info', () => {
    test('should show info alert when no backup data exists', () => {
      renderComponent(workspace);

      expect(screen.getByText('No backup information available')).toBeInTheDocument();
      expect(
        screen.getByText('Backup data for this workspace has not been recorded yet.'),
      ).toBeInTheDocument();
    });

    test('should display informational description', () => {
      renderComponent(workspace);

      expect(
        screen.getByText(/Backups are created automatically by the DevWorkspace Operator/),
      ).toBeInTheDocument();
    });

    test('snapshot - no backup info', () => {
      const snapshot = createSnapshot(workspace);
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('with backup info - success', () => {
    const backupInfo: BackupInfo = {
      status: BackupStatus.SUCCESS,
      lastBackupTime: '2026-02-11T12:30:00Z',
      backupImageUrl: 'registry.example.com/backups/my-workspace:latest',
      nextScheduledBackup: '2026-02-12T01:00:00Z',
    };

    test('should display backup status badge', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByTestId('backup-status-badge')).toBeInTheDocument();
      expect(screen.getByTestId('backup-status-badge')).toHaveTextContent(BackupStatus.SUCCESS);
    });

    test('should display last backup time', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByText('Last Backup')).toBeInTheDocument();
    });

    test('should display backup image URL with clipboard copy', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByText('Backup Image')).toBeInTheDocument();
      expect(
        screen.getByText('registry.example.com/backups/my-workspace:latest'),
      ).toBeInTheDocument();
    });

    test('should display next scheduled backup', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByText('Next Scheduled Backup')).toBeInTheDocument();
    });

    test('snapshot - success with all fields', () => {
      const snapshot = createSnapshot(workspace, { backupInfo });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('with backup info - never backed up', () => {
    const backupInfo: BackupInfo = {
      status: BackupStatus.NEVER,
    };

    test('should display never status', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByTestId('backup-status-badge')).toHaveTextContent(BackupStatus.NEVER);
    });

    test('should display "Never" for last backup time', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByText('Never')).toBeInTheDocument();
    });

    test('should not display backup image URL when not available', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.queryByText('Backup Image')).not.toBeInTheDocument();
    });

    test('should display "Not scheduled" when no next backup time', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByText('Not scheduled')).toBeInTheDocument();
    });

    test('snapshot - never status', () => {
      const snapshot = createSnapshot(workspace, { backupInfo });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('with backup info - failed', () => {
    const backupInfo: BackupInfo = {
      status: BackupStatus.FAILED,
      lastBackupTime: '2026-02-10T08:00:00Z',
      error: 'Registry authentication failed',
    };

    test('should display failed status', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByTestId('backup-status-badge')).toHaveTextContent(BackupStatus.FAILED);
    });

    test('snapshot - failed status', () => {
      const snapshot = createSnapshot(workspace, { backupInfo });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('with backup info - in progress', () => {
    const backupInfo: BackupInfo = {
      status: BackupStatus.IN_PROGRESS,
      lastBackupTime: '2026-02-11T10:00:00Z',
    };

    test('should display in-progress status', () => {
      renderComponent(workspace, { backupInfo });

      expect(screen.getByTestId('backup-status-badge')).toHaveTextContent(BackupStatus.IN_PROGRESS);
    });

    test('snapshot - in-progress status', () => {
      const snapshot = createSnapshot(workspace, { backupInfo });
      expect(snapshot.toJSON()).toMatchSnapshot();
    });
  });

  describe('loading with existing data', () => {
    test('should show backup info even when loading (not spinner)', () => {
      const backupInfo: BackupInfo = {
        status: BackupStatus.SUCCESS,
        lastBackupTime: '2026-02-11T12:30:00Z',
      };

      renderComponent(workspace, { backupInfo, isLoading: true });

      expect(screen.queryByLabelText('Loading backup information')).not.toBeInTheDocument();
      expect(screen.getByTestId('backup-status-badge')).toBeInTheDocument();
    });
  });
});

function getComponent(
  workspace: Workspace,
  options: {
    backupInfo?: BackupInfo;
    isLoading?: boolean;
    error?: string;
  } = {},
) {
  return (
    <BackupTab
      workspace={workspace}
      backupInfo={options.backupInfo}
      isLoading={options.isLoading || false}
      error={options.error}
      fetchWorkspaceBackupStatus={mockFetchBackupStatus}
    />
  );
}
